+/**
+ * Validates push notification payload to prevent crashes from invalid input
+ * @param {Object} data - The push notification data payload
+ * @param {string|string[]|Object} device - The device token(s)
+ * @returns {boolean} - True if valid, false otherwise
+ */
+function isValidPushNotification(data, device) {
+  // Validate data payload exists and is an object
+  if (!data || typeof data !== 'object' || Array.isArray(data)) {
+    return false;
+  }
+
+  // Validate device token
+  if (!isValidDeviceToken(device)) {
+    return false;
+  }
+
+  // Validate priority if provided
+  if (data.priority !== undefined && !isValidPriority(data.priority)) {
+    return false;
+  }
+
+  // Validate time-to-live if provided
+  if (data.timeToLive !== undefined && !isValidTTL(data.timeToLive)) {
+    return false;
+  }
+
+  return true;
+}
+
+function isValidDeviceToken(device) {
+  if (!device) {
+    return false;
+  }
+
+  // Handle single device token (string) or multiple device tokens (array)
+  if (typeof device === 'string') {
+    // Device token should be a non-empty string
+    return device.length > 0;
+  }
+
+  if (Array.isArray(device)) {
+    return device.length > 0 && device.every(token => typeof token === 'string' && token.length > 0);
+  }
+
+  return false;
+}
+
+function isValidPriority(priority) {
+  // APNS: 5 (immediate) or 10 (energy-efficient)
+  // GCM: 'normal' or 'high'
+  const validAPNSPriorities = [5, 10];
+  const validG CMPriorities = ['normal', 'high'];
+
+  return validAPNSPriorities.includes(priority) || validG CMPriorities.includes(priority);
+}
+
+function isValidTTL(ttl) {
+  // TTL should be a non-negative integer
+  return Number.isInteger(ttl) && ttl >= 0;
+}
+
